from typing import List

def count_bits(n: int) -> List[int]:
    def popcount(x):
        count = 0
        while x:
            count += x & 1
            x >>= 1
        return count
    return [popcount(i) for i in range(n + 1)]

from typing import List

def count_bits(n: int) -> List[int]:
    dp = [0] * (n + 1)
    for i in range(1, n + 1):
        dp[i] = dp[i >> 1] + (i & 1)
    return dp

